import { EventCategory } from '@/types';
import { Toast } from '@/hooks/use-toast'; // ✨ إذا كان عندك use-toast مخصص، import النوع من هون

export const fetchEvent = async (
  setLoading: (loading: boolean) => void,
  token: string,
  eventId: string,
  role?: string,
  toast?: Toast['toast'] // نوع toast الصحيح
): Promise<EventCategory | null> => {
  try {
    let urlRole = `http://localhost:8080/${role}/events/${eventId}`;
    let url = `http://localhost:8080/${role}/events/${eventId}`;
    const res = await fetch(`${role ? urlRole : url}`, {
      method: 'GET',
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
    });

    if (!res.ok) {
      throw new Error(`Failed to fetch event: ${res.statusText}`);
    }

    const data = await res.json();
    return data.event;
  } catch (error: unknown) {
    if (error instanceof Error) {
      toast({
        title: 'Error',
        description: error.message,
        variant: 'destructive',
      });
    } else {
      toast({
        title: 'Error',
        description: 'An unexpected error occurred.',
        variant: 'destructive',
      });
    }
    return null;
  } finally {
    setLoading(false);
  }
};
